import cv2
import numpy as np
import urllib.request
import threading
import time

POST_URL = 'https://maestra-dashboard-production.up.railway.app/video/frame/td'
_sending = False
_last_send = 0
SEND_INTERVAL = 0.1

def _send_frame(jpeg_data):
    global _sending
    try:
        req = urllib.request.Request(POST_URL, data=jpeg_data, method='POST')
        req.add_header('Content-Type', 'image/jpeg')
        urllib.request.urlopen(req, timeout=2)
    except:
        pass
    _sending = False

def onStart():
    return

def onCreate():
    return

def onExit():
    return

def onFrameStart(frame):
    global _sending, _last_send
    now = time.time()
    if now - _last_send < SEND_INTERVAL:
        return
    if _sending:
        return

    # Get StreamDiffusion output via flip1
    sd_out = op('/project1/flip1')
    if not sd_out or sd_out.width == 0:
        return

    try:
        arr = sd_out.numpyArray(delayed=True)
        if arr is None:
            return

        rgb = (arr[:,:,:3] * 255).astype(np.uint8)
        bgr = cv2.cvtColor(rgb, cv2.COLOR_RGB2BGR)
        bgr = cv2.flip(bgr, 0)

        ret, jpeg = cv2.imencode('.jpg', bgr, [cv2.IMWRITE_JPEG_QUALITY, 70])
        if ret:
            _sending = True
            _last_send = now
            t = threading.Thread(target=_send_frame, args=(jpeg.tobytes(),), daemon=True)
            t.start()
    except:
        pass

